.darma-loader-darma-custom-493 {color: var(--loader-color, #b45309);
   height: 35px;
   width: 80px;
   margin-left: 0px;
   background: radial-gradient(farthest-side,var(--loader-secondary-color, #fcd34d) 94%,#0000 ) 4px 22px/5px 5px, radial-gradient(farthest-side,var(--loader-secondary-color, #fcd34d) 94%,#0000 ) 12px 18px/5px 5px, radial-gradient(farthest-side,var(--loader-secondary-color, #fcd34d) 94%,#0000 ) 3px 6px/8px 8px, radial-gradient(farthest-side,var(--loader-secondary-color, #fcd34d) 90%,#0000 94%) left/20px 100%, var(--loader-color, #b45309);
   background-repeat: no-repeat;
   border-radius: 0 50px 50px 0;
   border-top-left-radius: 30px 40px;
   border-bottom-left-radius: 30px 40px;
   animation: darma-loader-darma-custom-493-l7 3s infinite steps(10);
   position: relative;
}
.darma-loader-darma-custom-493::before  {
  content: " ";
   position: absolute;
   inset: calc(50% - 8px) -10px calc(50% - 8px) auto;
   width: 15px;
   background: var(--loader-color, #b45309);
   clip-path: polygon(0 50%,100% 0,70% 50%,100% 100%);
}
@keyframes darma-loader-darma-custom-493-l7  {
  100% {width: 20px;
  margin-left:60px;
}
}

